class Solution {
public:
    int clumsy(int n) {
        int res = n;
        n--;
        bool op = true;
        while (n > 0) {
            if (op) {
                res = res * n;
            } else if (op == false && n % 2 == 1) {
                res = res / n;
            } else if (op == false && n % 2 == 0) {
                res = res + n;
            }
            op = !op;
            n--;
            if (n > 0 && op == false) {
                res = res - n;
                n--;
            }
        }
        return res;
    }
};

